import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");

        // Read user input
        String name = scanner.nextLine();

        // Validate input to prevent buffer overflow
        if (name.length() > 50) {
            System.out.println("Name exceeds maximum length. Please try again.");
            return;
        }

        // Construct welcome message using proper bounds checking
        String welcomeMessage = "Welcome, " + sanitizeInput(name) + "!";

        System.out.println(welcomeMessage);
    }

    // Sanitize input to prevent special characters or control characters
    private static String sanitizeInput(String input) {
        return input.replaceAll("[^a-zA-Z0-9]", "");
    }
}

